import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"桌面端快捷键","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/desktop-tools/keyboard-shortcuts.md","filePath":"zh-CN/stock-trading/desktop-tools/keyboard-shortcuts.md"}'),o={name:"stock-trading/desktop-tools/keyboard-shortcuts.md"};function h(l,t,n,i,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="桌面端快捷键" tabindex="-1">桌面端快捷键 <a class="header-anchor" href="#桌面端快捷键" aria-label="Permalink to &quot;桌面端快捷键&quot;">​</a></h1><p>桌面端全局和功能性快捷键、交易快捷键及自定义规则。</p><h2 id="快捷键层级说明" tabindex="-1">快捷键层级说明 <a class="header-anchor" href="#快捷键层级说明" aria-label="Permalink to &quot;快捷键层级说明&quot;">​</a></h2><ul><li>全局快捷键：在任意界面下均可触发，无需聚焦特定组件</li><li>功能快捷键：需要鼠标焦点位于对应组件内才可触发</li></ul><h2 id="常用功能快捷键" tabindex="-1">常用功能快捷键 <a class="header-anchor" href="#常用功能快捷键" aria-label="Permalink to &quot;常用功能快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Tab</td><td>切换到下一个输入项</td></tr><tr><td>Shift+Tab</td><td>切换到上一个输入项</td></tr><tr><td>Enter</td><td>确认/提交</td></tr><tr><td>Esc</td><td>取消/关闭弹窗</td></tr><tr><td>方向键 ↑↓</td><td>上下移动选中项或调整数值</td></tr></tbody></table><h2 id="全局快捷键" tabindex="-1">全局快捷键 <a class="header-anchor" href="#全局快捷键" aria-label="Permalink to &quot;全局快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>Mac</th><th>Windows</th></tr></thead><tbody><tr><td>新开标签页</td><td>Command+T</td><td>Ctrl+T</td></tr><tr><td>切换到前一个标签页</td><td>Command+[</td><td>Ctrl+[</td></tr><tr><td>切换到后一个标签页</td><td>Command+]</td><td>Ctrl+]</td></tr><tr><td>组件快速切换（长按）</td><td>Option（长按）</td><td>Alt（长按）</td></tr><tr><td>打开组件工具箱</td><td>Command+E</td><td>Ctrl+E</td></tr><tr><td>打开操作菜单</td><td>Command+K</td><td>Ctrl+K</td></tr><tr><td>打开交易弹窗</td><td>Command+O</td><td>Ctrl+O</td></tr><tr><td>向上翻页</td><td>Command+↑</td><td>Ctrl+↑</td></tr><tr><td>向下翻页</td><td>Command+↓</td><td>Ctrl+↓</td></tr><tr><td>快捷键说明页</td><td>Command+/</td><td>Ctrl+/</td></tr><tr><td>打开设置弹窗</td><td>Command+,</td><td>Ctrl+,</td></tr></tbody></table><h2 id="交易快捷键" tabindex="-1">交易快捷键 <a class="header-anchor" href="#交易快捷键" aria-label="Permalink to &quot;交易快捷键&quot;">​</a></h2><h3 id="全局通用-任意界面" tabindex="-1">全局通用（任意界面） <a class="header-anchor" href="#全局通用-任意界面" aria-label="Permalink to &quot;全局通用（任意界面）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>Mac</th><th>Windows</th></tr></thead><tbody><tr><td>买入弹窗</td><td>Command+B</td><td>Ctrl+B</td></tr><tr><td>卖出弹窗</td><td>Command+S</td><td>Ctrl+S</td></tr><tr><td>今日订单弹窗</td><td>Command+D</td><td>Ctrl+D</td></tr></tbody></table><h3 id="快速下单-焦点在交易组件时" tabindex="-1">快速下单（焦点在交易组件时） <a class="header-anchor" href="#快速下单-焦点在交易组件时" aria-label="Permalink to &quot;快速下单（焦点在交易组件时）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>B</td><td>买入</td></tr><tr><td>S</td><td>卖出</td></tr><tr><td>Enter</td><td>确认下单</td></tr></tbody></table><h2 id="快速撤单-改单快捷键" tabindex="-1">快速撤单/改单快捷键 <a class="header-anchor" href="#快速撤单-改单快捷键" aria-label="Permalink to &quot;快速撤单/改单快捷键&quot;">​</a></h2><p>在订单列表组件中，选中订单后可使用：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Delete / Backspace</td><td>撤销选中订单</td></tr><tr><td>E</td><td>改单</td></tr></tbody></table><h2 id="自定义快捷键规则" tabindex="-1">自定义快捷键规则 <a class="header-anchor" href="#自定义快捷键规则" aria-label="Permalink to &quot;自定义快捷键规则&quot;">​</a></h2><p>支持两类自定义快捷键：</p><ul><li>单键：F1–F12 或标点符号键</li><li>组合键：Command/Ctrl + 数字、字母或标点符号</li></ul><p>自定义设置入口：设置 &gt; 快捷键。</p>',20)])])}const u=d(o,[["render",h]]);export{c as __pageData,u as default};
